var objectCache = new Array();

(function($) {
	
	$.fn.tablify = function(setting){
		
		var defaults = $.extend({
			"src":"table.js",
			"table":this,
			"tableSetting":{},
			"refreshRate":"10",
			"objectCache":1,
			"extraField":[],
			"extraTarget":[],
			"extraClass":[]
		},setting);
		
		function genTable(){
			var time= new Date().getTime();
			var dataSource = defaults.src + ((defaults.src.indexOf("?")>0)?"&s="+time:"?s="+time);
			
			$.getJSON(dataSource,function(data){
				var table = data;
				objectCache[defaults.objectCache] = data;
				var extraField = defaults.extraField;
				var extraTarget = defaults.extraTarget;
				var extraClass = defaults.extraClass;
				if(extraTarget!=null&&extraField!=null){
					for(var e=0;e<extraTarget.length;e++){
						$("#"+extraTarget[e]).html(data[extraField[e]]);
						if(extraClass[e]){
							$("#"+extraTarget[e]).addClass(data[extraClass[e]]);
						}
					}
				}
				//console.log("in function: "+JSON.stringify(objectCache));
				console.log("table json:"+JSON.stringify(table));
				if(table!=null){
					var jsonTable = table;
					var targetTable = defaults.table;
					var settingTable = defaults.tableSetting;
					
					var table_header = settingTable.header;
					var table_header_align = settingTable.headerAlign;
					var table_header_class = settingTable.headerClass;
					var table_rows = jsonTable.tabledata;
					var table_mode = settingTable.mode;
					var table_border = settingTable.border;
					var table_cellspacing = settingTable.cellspacing;
					var table_cellpadding = settingTable.cellpadding;				
					var table_bgColor = settingTable.bgColor;
					var class_evenrow = settingTable.evenRowClass;
					var class_oddrow = settingTable.oddRowClass;
					var class_row = settingTable.rowClass;
					var class_column = settingTable.columnClass;
					var column_width = settingTable.columnWidth;
					var row_height = settingTable.rowHeight;
					var column_align = settingTable.columnAlign;
					var first_column_class = settingTable.firstColumnClass;
					var last_column_class = settingTable.lastColumnClass;
					var column_data = settingTable.columnData;
					var column_data_class = settingTable.columnDataClass;
					$(targetTable).html("");
					$(targetTable).css("background-color",table_bgColor);
					$(targetTable).css("border",table_border);
					$(targetTable).attr("cellspacing",table_cellspacing);
					$(targetTable).attr("cellpadding",table_cellpadding);
					var row,column,col_width,col_align;
					if(table_header!=null){
						row = $("<tr></tr>");
						row_height!=null?$(row).css("height",row_height):"";
						for(var i=0;i<table_header.length;i++){
							column = $("<th>"+table_header[i]+"</th>");
							(table_header_align)?$(column).css("text-align",table_header_align[i]):((column_align)?$(column).css("text-align",column_align[i]):"");
							(table_header_class)?$(column).addClass(table_header_class[i]):"";
							row.append(column);
						}
						targetTable.append(row);
					}
					if(table_rows!=null){
						for(var k=0;k<table_rows.length;k++){
							row = $("<tr></tr>");
							table_mode=="xy"?((k%2==0)?$(row).addClass(class_oddrow):$(row).addClass(class_evenrow)):$(row).addClass(class_row);
							row_height!=null?$(row).css("height",row_height):"";
							var table_columns = table_rows[k];
							if(table_columns!=null&&column_data!=null){
								for(var j=0;j<column_data.length;j++){
									var colDt = column_data[j];									
									var table_column_text = table_columns[colDt];
									if(table_column_text!=null){
										column = $("<td>"+table_column_text+"</td>");
										column_align[j]!=null?$(column).css("text-align",column_align[j]):"";
										column_width[j]!=null?$(column).css("width",column_width[j]):"";
										
										if(j==0){
											$(column).addClass((first_column_class!=null)?first_column_class:class_column);
										}else if(j==(column_data.length-1)){
											$(column).addClass((last_column_class!=null)?last_column_class:class_column);
										}else{
											class_column!=null?$(column).addClass(class_column):"";
										}
										
									}else{
										column = $("<td></td>");
									}
									if(column_data_class){
										if(column_data_class[j]){
											var table_column_class = table_columns[column_data_class[j]];
											$(column).addClass(table_column_class);
										}
									}
									row.append(column);
								}
								targetTable.append(row);
							}
						}
					}
				}
			}).error(function(jqXHR, textStatus, errorThrown) { /*alert('getJSON request failed! ' + textStatus);*/ });	
		}
		genTable();
		if(defaults.refreshRate>0){
			var miliseconds = defaults.refreshRate*1000;
			setInterval(function (){genTable();},miliseconds);
		}
		
	}; 
}(jQuery));